// services/iteration.service.ts
import api from './api'

export const iterationService = {
  // 获取迭代列表
  async getIterations(params: {
    page: number
    pageSize: number
    status?: string
    startDate?: string
    endDate?: string
  }) {
    const response = await api.get('/iterations', { params })
    return response.data
  },

  // 获取迭代详情
  async getIterationDetail(id: string) {
    const response = await api.get(`/iterations/${id}`)
    return response.data
  },

  // 获取当前迭代
  async getCurrentIteration() {
    const response = await api.get('/iterations/current')
    return response.data
  },

  // 回滚迭代
  async rollbackIteration(id: string) {
    const response = await api.post(`/iterations/${id}/rollback`)
    return response.data
  },

  // 对比迭代
  async compareIterations(id1: string, id2: string) {
    const response = await api.get(`/iterations/${id1}/diff/${id2}`)
    return response.data
  }
}
```

#### 3.2 完善 Iterations.vue 页面数据加载

