<!-- views/Iterations.vue -->
<script setup lang="ts">
import { ref, onMounted, computed } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { iterationService } from '@/services/iteration.service'

const iterations = ref([])
const loading = ref(false)
const searchKeyword = ref('')
const statusFilter = ref('')
const currentPage = ref(1)
const pageSize = ref(20)
const total = ref(0)

// 加载迭代列表
async function loadIterations() {
  loading.value = true
  try {
    const response = await iterationService.getIterations({
      page: currentPage.value,
      pageSize: pageSize.value,
      status: statusFilter.value || undefined
    })
    iterations.value = response.data
    total.value = response.total
  } catch (error) {
    ElMessage.error('加载迭代列表失败')
    console.error(error)
  } finally {
    loading.value = false
  }
}

// 搜索
function handleSearch() {
  currentPage.value = 1
  loadIterations()
}

// 筛选
function handleFilter() {
  currentPage.value = 1
  loadIterations()
}

// 查看详情
function viewDetail(iteration: any) {
  // 实现详情查看逻辑
  console.log('查看详情:', iteration)
}

// 回滚
async function rollback(iteration: any) {
  try {
    await ElMessageBox.confirm(
      `确定要回滚到迭代 #${iteration.iterationNumber} 吗？`,
      '确认回滚',
      { type: 'warning' }
    )

    await iterationService.rollbackIteration(iteration.id)
    ElMessage.success('回滚成功')
    loadIterations()
  } catch (error) {
    if (error !== 'cancel') {
      ElMessage.error('回滚失败')
      console.error(error)
    }
  }
}

onMounted(() => {
  loadIterations()
})
</script>
```

