// src/dashboard/integration/auto-iteration-integration.ts

import { AutoIterationEngine } from '../auto-iteration';
import { IterationService } from '../dashboard/services/iteration.service';
import { RealtimeService } from '../dashboard/services/realtime.service';

export class AutoIterationDashboardIntegration {
  private iterationService: IterationService;
  private realtimeService: RealtimeService;

  constructor(
    private engine: AutoIterationEngine,
    iterationService: IterationService,
    realtimeService: RealtimeService
  ) {
    this.iterationService = iterationService;
    this.realtimeService = realtimeService;
  }

  /**
   * 启动集成监控
   */
  async startMonitoring() {
    // 监听迭代开始
    this.engine.on('iteration:start', async (data) => {
      // 保存到数据库
      await this.iterationService.create({
        iterationNumber: data.iteration,
        status: 'running',
        requirement: data.task,
        startedAt: new Date()
      });

      // 推送到前端
      this.realtimeService.broadcastIterationStatusChange({
        iterationId: data.iteration.toString(),
        status: 'running',
        timestamp: new Date()
      });
    });

    // 监听迭代进度
    this.engine.on('iteration:progress', (data) => {
      this.realtimeService.broadcastIterationProgress({
        iterationId: data.iteration.toString(),
        phase: data.phase,
        progress: data.progress,
        message: data.message
      });
    });

    // 监听 Agent 状态变化
    this.engine.on('agent:start', (data) => {
      this.realtimeService.broadcastAgentStatusChange({
        agentName: data.agent,
        status: 'running',
        task: data.task,
        startTime: new Date()
      });
    });

    this.engine.on('agent:complete', (data) => {
      this.realtimeService.broadcastAgentStatusChange({
        agentName: data.agent,
        status: 'completed',
        result: data.result,
        endTime: new Date()
      });
    });

    // 监听迭代完成
    this.engine.on('iteration:complete', async (data) => {
      await this.iterationService.update(data.iteration.toString(), {
        status: data.status,
        completedAt: new Date(),
        result: data.message
      });

      this.realtimeService.broadcastIterationStatusChange({
        iterationId: data.iteration.toString(),
        status: data.status,
        timestamp: new Date()
      });
    });
  }
}
