// dashboard/src/stores/iteration.ts

import { defineStore } from 'pinia';
import { ref } from 'vue';
import { dashboardApi } from '@/api/dashboard';

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<any[]>([]);
  const currentIteration = ref<any | null>(null);
  const loading = ref(false);

  // 获取迭代列表
  async function fetchIterations(params: any) {
    loading.value = true;
    try {
      const response = await dashboardApi.getIterations(params);
      iterations.value = response.items;
      return response;
    } finally {
      loading.value = false;
    }
  }

  // 获取当前迭代
  async function fetchCurrentIteration() {
    const response = await dashboardApi.getIterationDetail('current');
    currentIteration.value = response;
  }

  // 更新迭代（从 WebSocket）
  function updateIteration(iteration: any) {
    const index = iterations.value.findIndex(i => i.id === iteration.id);
    if (index !== -1) {
      iterations.value[index] = iteration;
    } else {
      iterations.value.unshift(iteration);
    }
  }

  // 更新进度
  function updateProgress(progress: number) {
    if (currentIteration.value) {
      currentIteration.value.progress = progress;
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    fetchIterations,
    fetchCurrentIteration,
    updateIteration,
    updateProgress
  };
});
```

