```typescript
// dashboard/src/stores/log.ts

import { defineStore } from 'pinia';
import { ref } from 'vue';

export const useLogStore = defineStore('log', () => {
  const logs = ref<any[]>([]);

  // 添加日志
  function addLog(log: any) {
    logs.value.push({
      ...log,
      id: Date.now() + Math.random()
    });

    // 限制日志数量
    if (logs.value.length > 1000) {
      logs.value = logs.value.slice(-1000);
    }
  }

  // 清空日志
  function clearLogs() {
    logs.value = [];
  }

  return {
    logs,
    addLog,
    clearLogs
  };
});
