<!-- dashboard/src/components/LogViewer.vue -->
<template>
  <div class="log-viewer">
    <!-- 日志控制栏 -->
    <div class="control-bar">
      <el-input
        v-model="searchKeyword"
        placeholder="搜索日志..."
        clearable
      >
        <template #prefix>
          <el-icon><Search /></el-icon>
        </template>
      </el-input>

      <el-select v-model="levelFilter" placeholder="日志级别">
        <el-option label="全部" value="all" />
        <el-option label="ERROR" value="error" />
        <el-option label="WARN" value="warn" />
        <el-option label="INFO" value="info" />
        <el-option label="DEBUG" value="debug" />
      </el-select>

      <el-button @click="exportLogs">导出</el-button>

      <el-button
        :type="autoScroll ? 'primary' : 'default'"
        @click="autoScroll = !autoScroll"
      >
        自动滚动: {{ autoScroll ? '开' : '关' }}
      </el-button>
    </div>

    <!-- 日志内容 -->
    <div class="log-content" ref="logContainer">
      <div
        v-for="log in filteredLogs"
        :key="log.id"
        :class="['log-item', `log-${log.level}`]"
      >
        <span class="timestamp">{{ formatTime(log.timestamp) }}</span>
        <span class="level">[{{ log.level }}]</span>
        <span class="agent">{{ log.agent }}</span>
        <span class="message">{{ log.message }}</span>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, nextTick } from 'vue';

const props = defineProps<{
  logs: any[];
  realtime?: boolean;
}>();

const searchKeyword = ref('');
const levelFilter = ref('all');
const autoScroll = ref(true);
const logContainer = ref<HTMLElement>();

// 过滤日志
const filteredLogs = computed(() => {
  return props.logs.filter(log => {
    if (searchKeyword.value && !log.message.includes(searchKeyword.value)) {
      return false;
    }
    if (levelFilter.value !== 'all' && log.level !== levelFilter.value) {
      return false;
    }
    return true;
  });
});

// 自动滚动
watch(filteredLogs, () => {
  if (autoScroll.value) {
    nextTick(() => {
      if (logContainer.value) {
        logContainer.value.scrollTop = logContainer.value.scrollHeight;
      }
    });
  }
}, { deep: true });

// 导出日志
function exportLogs() {
  const content = filteredLogs.value.map(log =>
    `[${log.timestamp}] [${log.level}] ${log.message}`
  ).join('\n');

  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `logs-${Date.now()}.txt`;
  a.click();
}

function formatTime(timestamp: string) {
  return new Date(timestamp).toLocaleTimeString();
}
</script>

